<script setup>
import {computed,onMounted,ref} from 'vue';import {useRoute,useRouter} from 'vue-router';import {getProductById} from '../api/productApi';import {useAuthStore} from '../stores/auth';import {useCartStore} from '../stores/cart'
const route=useRoute(),router=useRouter(),auth=useAuthStore(),cart=useCartStore(),product=ref(null),loading=ref(true),adding=ref(false),error=ref(''),success=ref(''),activeImage=ref(''),quantity=ref(1)
const gallery=computed(()=>{const list=product.value?.images?.map(i=>i.imageUrl)||[];if(product.value?.imageUrl&&!list.includes(product.value.imageUrl))list.unshift(product.value.imageUrl);return list}),money=value=>new Intl.NumberFormat('zh-TW',{style:'currency',currency:'TWD',maximumFractionDigits:0}).format(value||0)
async function add(){if(!auth.isAuthenticated)return router.push({path:'/login',query:{redirect:route.fullPath}});adding.value=true;error.value='';success.value='';try{await cart.add(product.value.id,Number(quantity.value));success.value='商品已加入購物車。'}catch(e){error.value=e.message}finally{adding.value=false}}
onMounted(async()=>{try{product.value=await getProductById(route.params.id);activeImage.value=gallery.value[0]||''}catch(e){error.value=e.message}finally{loading.value=false}})
</script>
<template><div class="container-wide detail-page"><RouterLink class="back-link" to="/products">← 返回商品列表</RouterLink><div v-if="loading" class="detail-skeleton skeleton"></div><p v-else-if="error&&!product" class="alert error">{{error}}</p><section v-else-if="product" class="product-detail"><div class="gallery"><div class="gallery-main"><img v-if="activeImage" :src="activeImage" :alt="product.productName"><span v-else>SECOND PHONE</span></div><div v-if="gallery.length>1" class="gallery-thumbs"><button v-for="image in gallery" :key="image" :class="{active:image===activeImage}" @click="activeImage=image"><img :src="image" alt="商品縮圖"></button></div></div><div class="product-info"><div class="product-meta"><span>{{product.brand}}</span><span>{{product.productCode}}</span></div><h1>{{product.productName}}</h1><p class="product-model">{{product.model}}・{{product.storageCapacity}}・{{product.color}}</p><strong class="detail-price">{{money(product.price)}}</strong><div class="detail-badges"><span class="badge">{{product.conditionLevel}}</span><span :class="['badge',product.availableStock?'badge-success':'badge-danger']">{{product.availableStock?`現貨 ${product.availableStock}`:'缺貨'}}</span></div><dl class="spec-list"><div><dt>品牌</dt><dd>{{product.brand}}</dd></div><div><dt>分類</dt><dd>{{product.category||'二手手機'}}</dd></div><div><dt>型號</dt><dd>{{product.model}}</dd></div><div><dt>容量</dt><dd>{{product.storageCapacity||'-'}}</dd></div><div><dt>顏色</dt><dd>{{product.color||'-'}}</dd></div><div><dt>機況</dt><dd>{{product.conditionLevel}}</dd></div></dl><p class="description">{{product.description||'此商品尚未提供詳細說明。'}}</p><p v-if="error" class="alert error">{{error}}</p><p v-if="success" class="alert success">{{success}}</p><div class="quantity-row"><label>數量<input v-model.number="quantity" type="number" min="1" :max="product.availableStock"></label><button class="button button-primary button-grow" :disabled="adding||product.availableStock<=0" @click="add">{{adding?'加入中…':'加入購物車'}}</button></div><div class="guarantee-card"><strong>Second Phone 品質保障</strong><p>商品規格、機況與庫存由平台統一管理，訂單與服務歷程皆可追蹤。</p></div></div></section></div></template>
